oxy_webhelp_navlinks = {"K8s_crd_rsc-d23535e19569":{"topics":[{"title":"Kubernetes ClusterRoles","shortdesc":"<p class=\"shortdesc\"><span class=\"ph\">RSC<\/span> includes the kupr-admin and kupr-user ClusterRoles.<\/p>","href":"kubernetes\/k8s_clusterroles.html","attributes":{"data-id":"k8s_clusterroles"},"menu":{"hasChildren":false},"tocID":"k8s_clusterroles-d23535e19585","topics":[]},{"title":"Kubernetes Protection CRD requirements","shortdesc":"<p class=\"shortdesc\">To use Kubernetes Protection custom resource definitions you must have certain         resources available.<\/p>","href":"kubernetes\/k8s_crd_prerqs.html","attributes":{"data-id":"k8s_crd_prerqs"},"menu":{"hasChildren":false},"tocID":"k8s_crd_prerqs-d23535e19598","topics":[]},{"title":"Kubernetes protection CRDs","shortdesc":"<p class=\"shortdesc\">You can perform backup and recovery workflows using native APIs for Kubernetes by         using the Rubrik custom resource definitions.<\/p>","href":"kubernetes\/k8s_custom_resources_k8s_protection.html","attributes":{"data-id":"k8s_custom_resources_k8s_protection"},"menu":{"hasChildren":false},"tocID":"k8s_custom_resources_k8s_protection-d23535e19609","topics":[]},{"title":"Verifying the Kubernetes cluster resources","shortdesc":"<p class=\"shortdesc\">Verify that the resources available on a Kubernetes cluster are adequate for the <span class=\"ph\">RSC<\/span> custom resources.<\/p>","href":"kubernetes\/k8s_validate_k8s_cluster_resources.html","attributes":{"data-id":"k8s_validate_k8s_cluster_resources"},"menu":{"hasChildren":false},"tocID":"k8s_validate_k8s_cluster_resources-d23535e19620","topics":[]},{"title":"Creating role bindings for working with CRDs","shortdesc":"<p class=\"shortdesc\">Create kupr-user and kupr-namespace-user role bindings for users that work with         Kubernetes custom resource definitions.<\/p>","href":"kubernetes\/k8s_create_bindings_k8s_crd.html","attributes":{"data-id":"k8s_create_bindings_k8s_crd"},"menu":{"hasChildren":false},"tocID":"k8s_create_bindings_k8s_crd-d23535e19634","topics":[]},{"title":"Custom resource definition examples","shortdesc":"<p class=\"shortdesc\">The examples in this section use the <span class=\"ph\">RSC<\/span> custom resource definitions         to create custom resources for backup and recovery, for assigning SLA Domains, performing         on-demand shots, and for many other operations typically done using the <span class=\"ph\">RSC<\/span>         UI.<\/p>","href":"kubernetes\/custom_resource_definition_examples.html","attributes":{"data-id":"custom_resource_definition_examples"},"menu":{"hasChildren":false},"tocID":"custom_resource_definition_examples-d23535e19645","next":"custom_resource_definition_examples-d23535e19645"},{"title":"Hook CRD","shortdesc":"<p class=\"shortdesc\">The Hook custom resource definition can be used to run commands before and after         running a backup of a protection set.<\/p>","href":"kubernetes\/k8s_hook_crd.html","attributes":{"data-id":"k8s_hook_crd"},"menu":{"hasChildren":false},"tocID":"k8s_hook_crd-d23535e19750","next":"k8s_hook_crd-d23535e19750"},{"title":"K8SCluster CRD","shortdesc":"<p class=\"shortdesc\">The K8SCluster custom resource definition creates a read-only custom resource that         provides information about your Kubernetes clusters.<\/p>","href":"kubernetes\/k8s_cluster.html","attributes":{"data-id":"k8s_cluster"},"menu":{"hasChildren":false},"tocID":"k8s_cluster-d23535e19783","next":"k8s_cluster-d23535e19783"},{"title":"ProtectionSet CRD","shortdesc":"<p class=\"shortdesc\">The ProtectionSet custom resource definition provides information about an         application in the Kubernetes cluster. Rubrik Kubernetes data protection can use a         ProtectionSet custom resource to protect that application.<\/p>","href":"kubernetes\/k8s_protectionset.html","attributes":{"data-id":"k8s_protectionset"},"menu":{"hasChildren":false},"tocID":"k8s_protectionset-d23535e19816","next":"k8s_protectionset-d23535e19816"},{"title":"RecoveryJob CRD","shortdesc":"<p class=\"shortdesc\">The RecoveryJob CRD defines a namespace-level recovery job in the Rubrik cluster,         allowing application owners to use kubectl for snapshot recovery, with jobs retained as long         as tracked in the cluster metadata.<\/p>","href":"kubernetes\/k8s_recoveryjob.html","attributes":{"data-id":"k8s_recoveryjob"},"menu":{"hasChildren":false},"tocID":"k8s_recoveryjob-d23535e19849","next":"k8s_recoveryjob-d23535e19849"},{"title":"RubrikCluster CRD","shortdesc":"<p class=\"shortdesc\">The RubrikCluster custom resource definition can be used to view information about         the Rubrik clusters associated with a Kubernetes cluster.<\/p>","href":"kubernetes\/k8s_rubrikcluster.html","attributes":{"data-id":"k8s_rubrikcluster"},"menu":{"hasChildren":false},"tocID":"k8s_rubrikcluster-d23535e19883","next":"k8s_rubrikcluster-d23535e19883"},{"title":"SLADomain CRD","shortdesc":"<p class=\"shortdesc\">The SLADomain custom resource definition provides information about the SLA Domains         in a Rubrik cluster.<\/p>","href":"kubernetes\/k8s_sladomain.html","attributes":{"data-id":"k8s_sladomain"},"menu":{"hasChildren":false},"tocID":"k8s_sladomain-d23535e19916","next":"k8s_sladomain-d23535e19916"},{"title":"Snapshot CRD","shortdesc":"<p class=\"shortdesc\">The Snapshot custom resource definition provides details about protection set         snapshots.<\/p>","href":"kubernetes\/k8s_snapshot.html","attributes":{"data-id":"k8s_snapshot"},"menu":{"hasChildren":false},"tocID":"k8s_snapshot-d23535e19949","next":"k8s_snapshot-d23535e19949"},{"title":"SnapshotJob CRD","shortdesc":"<p class=\"shortdesc\">The SnapshotJob custom resource definition allows you to create and manage on-demand         and policy-driven snapshot jobs.<\/p>","href":"kubernetes\/k8s_snapshotjob.html","attributes":{"data-id":"k8s_snapshotjob"},"menu":{"hasChildren":false},"tocID":"k8s_snapshotjob-d23535e19982","next":"k8s_snapshotjob-d23535e19982"}]}};